import { AppBar, Box, Dialog, DialogContent, DialogTitle, Icon, IconButton, makeStyles, TextField, Toolbar, Typography } from '@material-ui/core'
import { Assignment, AssignmentIndRounded, CloseRounded } from '@material-ui/icons'
import React from 'react'

const useStyles = makeStyles(theme => {
    return {
        root: {
            display: 'flex'
        },
        title: {
            display: 'flex', 
            alignContent: 'center'
        },
        icon: {
            marginRight: theme.spacing(0.5), 
            marginLeft: theme.spacing(0.5), 
        },
        white: {
            color: '#fefefe'
        }
    }
})

function CreateActivity() {
    const classes = useStyles()


  return (
    <Box className={classes.root}>
        <Dialog open={true} fullScreen>
            <DialogTitle>
                <AppBar color='secondary' elevation={0}>
                    <Toolbar>
                        <IconButton><CloseRounded className={classes.white} /></IconButton>
                        <Box className={classes.title}><Icon className={classes.icon}><Assignment /></Icon> Create Activity</Box>
                    </Toolbar>
                </AppBar>
            </DialogTitle>
            <DialogContent>
                    <Box >
                        <form action="">
                            <TextField fullWidth/>
                        </form>
                    </Box>
            </DialogContent>
        </Dialog>
    </Box>
  )
}

export default CreateActivity
